use aiken/collection/list
use aiken/interval
use cardano/assets
use cardano/transaction.{
  InlineDatum, Input, Output, OutputReference, Transaction,
}

pub type PoolDatum {
  reserve_a: Int,
  reserve_b: Int,
  lp_supply: Int,
}

pub type WithdrawRedeemer {
  lp_burn_amount: Int,
  lp_policy: ByteArray,
  lp_asset_name: ByteArray,
  token_a_policy: ByteArray,
  token_a_name: ByteArray,
  token_b_policy: ByteArray,
  token_b_name: ByteArray,
}

fn get_pool_datum(input: Input) -> Option<PoolDatum> {
  when input.output.datum is {
    InlineDatum(raw) -> {
      expect typed: PoolDatum = raw
      Some(typed)
    }
    _ -> None
  }
}

fn find_output_to_address(
  outputs: List<Output>,
  addr: cardano/address.Address,
) -> Option<Output> {
  list.find(outputs, fn(o) { o.address == addr })
}

fn abs_diff(a: Int, b: Int) -> Int {
  if a >= b {
    a - b
  } else {
    b - a
  }
}

fn proportional_check(
  lp_burn: Int,
  lp_supply: Int,
  reserve: Int,
  withdrawn: Int,
) -> Bool {
  // withdrawn / reserve == lp_burn / lp_supply
  // => withdrawn * lp_supply == lp_burn * reserve  (exact integer check)
  // Allow small rounding: withdrawn * lp_supply >= lp_burn * reserve - lp_supply
  //                   and withdrawn * lp_supply <= lp_burn * reserve
  let expected = lp_burn * reserve
  let actual = withdrawn * lp_supply
  // actual should be in [expected - lp_supply, expected]
  // i.e. floor division rounding down is acceptable
  actual <= expected && actual >= expected - lp_supply
}

validator lp_withdraw {
  spend(
    datum: Option<PoolDatum>,
    redeemer: WithdrawRedeemer,
    utxo: OutputReference,
    self: Transaction,
  ) {
    // Get the own input
    expect Some(own_input) =
      list.find(self.inputs, fn(i) { i.output_reference == utxo })

    // Read pool datum from own input inline datum
    expect Some(pool) = get_pool_datum(own_input)

    // Also verify datum parameter matches
    expect Some(d) = datum
    let lp_burn = redeemer.lp_burn_amount

    // Sanity checks
    let valid_burn = lp_burn > 0
    let valid_supply = pool.lp_supply > 0
    let valid_reserves = pool.reserve_a > 0 && pool.reserve_b > 0

    // Verify LP tokens are burned in the mint field (negative quantity)
    let burned_lp =
      assets.quantity_of(self.mint, redeemer.lp_policy, redeemer.lp_asset_name)
    let burn_correct = burned_lp == -lp_burn

    // Find continuing output back to pool address
    let pool_address = own_input.output.address
    expect Some(pool_out) = find_output_to_address(self.outputs, pool_address)

    // Read new pool datum
    expect InlineDatum(raw_out) = pool_out.datum
    expect new_pool: PoolDatum = raw_out

    // Compute how much of each token was withdrawn
    let pool_a_before =
      assets.quantity_of(
        own_input.output.value,
        redeemer.token_a_policy,
        redeemer.token_a_name,
      )
    let pool_b_before =
      assets.quantity_of(
        own_input.output.value,
        redeemer.token_b_policy,
        redeemer.token_b_name,
      )
    let pool_a_after =
      assets.quantity_of(
        pool_out.value,
        redeemer.token_a_policy,
        redeemer.token_a_name,
      )
    let pool_b_after =
      assets.quantity_of(
        pool_out.value,
        redeemer.token_b_policy,
        redeemer.token_b_name,
      )

    let withdrawn_a = pool_a_before - pool_a_after
    let withdrawn_b = pool_b_before - pool_b_after

    // Withdrawn amounts must be positive
    let positive_withdrawals = withdrawn_a > 0 && withdrawn_b > 0

    // Check proportionality: withdrawn_x / reserve_x == lp_burn / lp_supply
    let prop_a =
      proportional_check(lp_burn, pool.lp_supply, pool.reserve_a, withdrawn_a)
    let prop_b =
      proportional_check(lp_burn, pool.lp_supply, pool.reserve_b, withdrawn_b)

    // Verify new pool datum is consistent
    let new_reserve_a_correct = new_pool.reserve_a == pool.reserve_a - withdrawn_a
    let new_reserve_b_correct = new_pool.reserve_b == pool.reserve_b - withdrawn_b
    let new_supply_correct = new_pool.lp_supply == pool.lp_supply - lp_burn

    // Datum field consistency
    let datum_consistent =
      d.reserve_a == pool.reserve_a && d.reserve_b == pool.reserve_b && d.lp_supply == pool.lp_supply

    valid_burn && valid_supply && valid_reserves && burn_correct && positive_withdrawals && prop_a && prop_b && new_reserve_a_correct && new_reserve_b_correct && new_supply_correct && datum_consistent
  }

  else(_) {
    False
  }
}

use aiken/collection/list
use aiken/interval
use cardano/assets
use cardano/transaction.{
  InlineDatum, Input, Output, OutputReference, Transaction,
}

pub type SubDatum {
  subscriber: ByteArray,
  expiry: Int,
  fee_per_period: Int,
}

pub type SubRedeemer {
  Renew { new_expiry: Int }
  Cancel
}

fn find_own_input(inputs: List<Input>, utxo: OutputReference) -> Option<Input> {
  list.find(inputs, fn(i) { i.output_reference == utxo })
}

fn find_continuing_output(outputs: List<Output>, own_address: cardano/address.Address) -> Option<Output> {
  list.find(outputs, fn(o) { o.address == own_address })
}

validator subscription {
  spend(
    datum: Option<SubDatum>,
    redeemer: SubRedeemer,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    when redeemer is {
      Renew { new_expiry } -> {
        let signed_by_subscriber =
          list.has(self.extra_signatories, d.subscriber)

        expect Some(own_input) = find_own_input(self.inputs, utxo)
        let own_address = own_input.output.address

        expect Some(cont_out) =
          find_continuing_output(self.outputs, own_address)

        expect InlineDatum(raw) = cont_out.datum
        expect cont_datum: SubDatum = raw

        let datum_valid =
          cont_datum.subscriber == d.subscriber && cont_datum.expiry == new_expiry && cont_datum.fee_per_period == d.fee_per_period

        let new_expiry_greater = new_expiry > d.expiry

        let input_lovelace = assets.lovelace_of(own_input.output.value)
        let output_lovelace = assets.lovelace_of(cont_out.value)
        let fee_paid = output_lovelace >= input_lovelace + d.fee_per_period

        signed_by_subscriber && datum_valid && new_expiry_greater && fee_paid
      }

      Cancel -> {
        let signed_by_subscriber =
          list.has(self.extra_signatories, d.subscriber)

        let after_expiry =
          interval.is_entirely_after(self.validity_range, d.expiry)

        signed_by_subscriber && after_expiry
      }
    }
  }
}

use aiken/interval
use cardano/transaction.{InlineDatum, OutputReference, Transaction}

pub type TimelockDatum {
  recipient: ByteArray,
  unlock_time: Int,
}

validator timed_release {
  spend(
    datum: Option<TimelockDatum>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum
    let after_unlock = interval.is_entirely_after(self.validity_range, d.unlock_time)
    let signed_by_recipient = list.has(self.extra_signatories, d.recipient)
    after_unlock && signed_by_recipient
  }
}

