pub type EscrowDatum {
  seller: ByteArray,
  buyer: ByteArray,
  amount: Int,
  deadline: Int,
}

pub type EscrowRedeemer {
  Complete
  Refund
  Dispute
}

fn find_output_to(outputs: List<Output>, addr: Address) -> Option<Output> {
  list.find(outputs, fn(o) { o.address == addr })
}

fn address_from_pkh(pkh: ByteArray) -> Address {
  Address {
    payment_credential: cardano/address.VerificationKey(pkh),
    stake_credential: None,
  }
}

validator safe_escrow {
  spend(
    datum: Option<EscrowDatum>,
    redeemer: EscrowRedeemer,
    utxo: OutputReference,
    self: Transaction,
  ) {
    let own_input =
      list.find(self.inputs, fn(i) { i.output_reference == utxo })

    expect Some(input) = own_input

    when input.output.datum is {
      InlineDatum(raw) -> {
        expect d: EscrowDatum = raw
        when redeemer is {
          Complete -> {
            let seller_addr = Address {
              payment_credential: cardano/address.VerificationKey(d.seller),
              stake_credential: None,
            }
            let seller_paid =
              list.any(
                self.outputs,
                fn(o) {
                  o.address == seller_addr && assets.lovelace_of(o.value) >= d.amount
                },
              )
            let buyer_signed = list.has(self.extra_signatories, d.buyer)
            buyer_signed && seller_paid
          }
          Refund -> {
            let buyer_addr = Address {
              payment_credential: cardano/address.VerificationKey(d.buyer),
              stake_credential: None,
            }
            let buyer_paid =
              list.any(
                self.outputs,
                fn(o) {
                  o.address == buyer_addr && assets.lovelace_of(o.value) >= d.amount
                },
              )
            let seller_signed = list.has(self.extra_signatories, d.seller)
            seller_signed && buyer_paid
          }
          Dispute -> {
            let seller_signed = list.has(self.extra_signatories, d.seller)
            let buyer_signed = list.has(self.extra_signatories, d.buyer)
            seller_signed && buyer_signed
          }
        }
      }
      DatumHash(_) -> fail @"DatumHash not supported: only inline datums are accepted"
      NoDatum -> fail @"NoDatum not supported: only inline datums are accepted"
    }
  }
}

use aiken/collection/list
use aiken/interval
use cardano/assets
use cardano/transaction.{InlineDatum, Input, Output, OutputReference, Transaction}

pub type FundDatum {
  goal: Int,
  deadline: Int,
  creator: ByteArray,
}

pub type FundRedeemer {
  Withdraw
  Refund
}

fn total_locked_lovelace(inputs: List<Input>, own_address: cardano/address.Address) -> Int {
  list.foldl(
    inputs,
    0,
    fn(input, acc) {
      if input.output.address == own_address {
        acc + assets.lovelace_of(input.output.value)
      } else {
        acc
      }
    },
  )
}

validator crowdfund {
  spend(
    datum: Option<FundDatum>,
    redeemer: FundRedeemer,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    when redeemer is {
      Withdraw -> {
        let signed_by_creator =
          list.has(self.extra_signatories, d.creator)

        let after_deadline =
          interval.is_entirely_after(self.validity_range, d.deadline)

        expect Some(own_input) =
          list.find(
            self.inputs,
            fn(input) {
              when input.output.datum is {
                InlineDatum(raw) -> {
                  expect typed: FundDatum = raw
                  typed.creator == d.creator && typed.goal == d.goal && typed.deadline == d.deadline
                }
                _ -> False
              }
            },
          )

        let own_address = own_input.output.address

        let total_funds = total_locked_lovelace(self.inputs, own_address)

        let goal_met = total_funds >= d.goal

        signed_by_creator && after_deadline && goal_met
      }

      Refund -> {
        let after_deadline =
          interval.is_entirely_after(self.validity_range, d.deadline)

        expect Some(own_input) =
          list.find(
            self.inputs,
            fn(input) {
              when input.output.datum is {
                InlineDatum(raw) -> {
                  expect typed: FundDatum = raw
                  typed.creator == d.creator && typed.goal == d.goal && typed.deadline == d.deadline
                }
                _ -> False
              }
            },
          )

        let own_address = own_input.output.address

        let total_funds = total_locked_lovelace(self.inputs, own_address)

        let goal_not_met = total_funds < d.goal

        after_deadline && goal_not_met
      }
    }
  }
}

use aiken/collection/list
use cardano/address.{Address, VerificationKey}
use cardano/transaction.{InlineDatum, Output, OutputReference, Transaction}

pub type BatchDatum {
  recipients: List<ByteArray>,
  amounts: List<Int>,
  sender: ByteArray,
}

fn recipient_amount_pairs(
  recipients: List<ByteArray>,
  amounts: List<Int>,
) -> List<(ByteArray, Int)> {
  when recipients is {
    [] -> []
    [r, ..rest_r] ->
      when amounts is {
        [] -> []
        [a, ..rest_a] ->
          [(r, a), ..recipient_amount_pairs(rest_r, rest_a)]
      }
  }
}

fn output_satisfies_pair(
  outputs: List<Output>,
  recipient: ByteArray,
  amount: Int,
) -> Bool {
  list.any(
    outputs,
    fn(output) {
      let payment_matches =
        when output.address.payment_credential is {
          VerificationKey(pkh) -> pkh == recipient
          _ -> False
        }
      let amount_matches = lovelace_of(output.value) >= amount
      payment_matches && amount_matches
    },
  )
}

fn lovelace_of(value: cardano/assets.Value) -> Int {
  cardano/assets.lovelace_of(value)
}

fn all_pairs_satisfied(
  pairs: List<(ByteArray, Int)>,
  outputs: List<Output>,
) -> Bool {
  list.all(
    pairs,
    fn(pair) {
      let (recipient, amount) = pair
      output_satisfies_pair(outputs, recipient, amount)
    },
  )
}

validator batch_transfer {
  spend(
    datum: Option<BatchDatum>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum
    let sender_signed = list.has(self.extra_signatories, d.sender)
    let pairs = recipient_amount_pairs(d.recipients, d.amounts)
    let pairs_not_empty =
      when pairs is {
        [] -> False
        _ -> True
      }
    let all_satisfied = all_pairs_satisfied(pairs, self.outputs)
    sender_signed && pairs_not_empty && all_satisfied
  }
}
